export const nextGeneration = (cells: readonly Cell[]): Cell[] => {
  const isAlive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);
  const liveNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (isAlive(x + dx, y + dy)) count++;
      }
    }
    return count;
  };
  return cells.filter(([x, y]) => liveNeighbors(x, y) >= 2);
};

