    const n = liveNeighbors(x, y);
    const wasAlive = liveSet.has(key(x, y));
    if ((wasAlive && (n === 2 || n === 3)) || (!wasAlive && n === 3)) {
      result.push([x, y]);
    }
  }
  return result;
};

